import React, { useState } from 'react';
import axios from 'axios';
import Editor from '@monaco-editor/react';
import jsPDF from 'jspdf';
import html2canvas from 'html2canvas';
import { 
  Upload, FileCode, ShieldCheck, RefreshCw, 
  Eye, EyeOff, BarChart3, Terminal, Activity, ShieldAlert, Download
} from 'lucide-react';

// Sub-components
import RiskProfile from './components/RiskProfile';
import StatisticsTab from './components/StatisticsTab';

function App() {
  // --- UI & Navigation State ---
  const [activeTab, setActiveTab] = useState("analysis");
  const [viewMode, setViewMode] = useState("original");
  const [loading, setLoading] = useState(false);
  
  // --- Data State ---
  const [file, setFile] = useState(null);
  const [code, setCode] = useState("// 1. Upload a PHP script\n// 2. Initialize scan\n// 3. Review AI-generated risk profile");
  const [results, setResults] = useState(null);
  const [editorRef, setEditorRef] = useState(null);

  // --- Handlers ---
  const handleFileUpload = (e) => {
    const uploadedFile = e.target.files[0];
    if (uploadedFile) {
      setFile(uploadedFile);
      const reader = new FileReader();
      reader.onload = (e) => setCode(e.target.result);
      reader.readAsText(uploadedFile);
      setResults(null); 
    }
  };

  const applyHighlights = (evidence) => {
    if (!editorRef || !evidence || !window.monaco) return;
    const decorations = evidence.map(item => ({
      range: new window.monaco.Range(item.line, 1, item.line, 1),
      options: {
        isWholeLine: true,
        className: 'bg-red-900/30', 
        glyphMarginClassName: 'bg-red-500 rounded-full',
        hoverMessage: { value: `**Semantic Warning:** ${item.intent} behavior detected.` }
      }
    }));
    editorRef.deltaDecorations([], decorations);
  };

  const analyzeMalware = async () => {
    if (!file) return alert("Please select a file first!");
    setLoading(true);
    const formData = new FormData();
    formData.append("file", file);

    try {
      const response = await axios.post("http://localhost:8000/scan", formData);
      const scanResults = response.data.results;
      setResults(scanResults);
      if (scanResults.evidence) applyHighlights(scanResults.evidence);
    } catch (error) {
      console.error("Analysis failed", error);
      alert("Backend connection failed. Ensure FastAPI is running.");
    } finally {
      setLoading(false);
    }
  };

  const downloadReport = async () => {
    if (!results) return;
    const reportElement = document.getElementById('report-area');
    const canvas = await html2canvas(reportElement, { backgroundColor: '#0f172a', scale: 2 });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('p', 'mm', 'a4');
    
    pdf.setFontSize(20);
    pdf.setTextColor(37, 99, 235);
    pdf.text("PHPSentinel Intelligence Report", 15, 20);
    pdf.setFontSize(10);
    pdf.setTextColor(100);
    pdf.text(`Target File: ${file.name} | Date: ${new Date().toLocaleString()}`, 15, 28);
    
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
    pdf.addImage(imgData, 'PNG', 0, 40, pdfWidth, pdfHeight);
    pdf.save(`Intelligence_Report_${file.name}.pdf`);
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#0f172a] text-slate-300">
      
      {/* Header */}
      <nav className="h-20 border-b border-slate-800 bg-[#1e293b]/50 backdrop-blur-md px-8 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 p-2 rounded-xl shadow-lg shadow-blue-500/20">
            <ShieldCheck className="text-white" size={26} />
          </div>
          <div>
            <h1 className="text-xl font-bold text-white tracking-tight leading-none">PHPSentinel</h1>
            <p className="text-[10px] text-blue-400 font-bold tracking-widest mt-1">AI THREAT INTELLIGENCE</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <label className="flex items-center gap-2 px-4 py-2.5 bg-slate-800 hover:bg-slate-700 border border-slate-700 rounded-xl cursor-pointer transition-all text-sm font-medium">
            <Upload size={16} className="text-blue-400" />
            <span>{file ? file.name : "Select PHP Script"}</span>
            <input type="file" className="hidden" onChange={handleFileUpload} accept=".php" />
          </label>
          <button 
            onClick={analyzeMalware}
            disabled={loading}
            className="px-6 py-2.5 bg-blue-600 hover:bg-blue-500 text-white rounded-xl text-sm font-bold flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50"
          >
            {loading ? <RefreshCw className="animate-spin" size={18} /> : <Activity size={18} />}
            {loading ? "Analyzing..." : "Initialize Scan"}
          </button>
          {results && (
            <button onClick={downloadReport} className="p-2.5 bg-slate-800 text-slate-400 hover:text-white border border-slate-700 rounded-xl transition-all">
              <Download size={20} />
            </button>
          )}
        </div>
      </nav>

      <div className="flex flex-1 max-w-[1800px] mx-auto w-full p-6 gap-8">
        {/* Navigation Sidebar */}
        <aside className="w-64 flex flex-col gap-2 shrink-0">
          <button 
            onClick={() => setActiveTab("analysis")}
            className={`flex items-center gap-3 px-4 py-3.5 rounded-2xl text-sm font-bold transition-all ${activeTab === 'analysis' ? 'bg-blue-600/10 text-blue-400 border border-blue-600/20' : 'text-slate-500 hover:bg-slate-800/50 hover:text-slate-300'}`}
          >
            <Terminal size={20} /> Threat Detection
          </button>
          <button 
            onClick={() => setActiveTab("stats")}
            className={`flex items-center gap-3 px-4 py-3.5 rounded-2xl text-sm font-bold transition-all ${activeTab === 'stats' ? 'bg-blue-600/10 text-blue-400 border border-blue-600/20' : 'text-slate-500 hover:bg-slate-800/50 hover:text-slate-300'}`}
          >
            <BarChart3 size={20} /> Model Analytics
          </button>
          
          <div className="mt-auto p-5 bg-slate-900/50 rounded-3xl border border-slate-800">
            <div className="flex items-center gap-2 text-blue-400 mb-3">
              <ShieldAlert size={16} />
              <span className="text-xs font-black uppercase tracking-widest">Model Status</span>
            </div>
            <p className="text-xs text-slate-500 leading-relaxed font-medium">
              CodeBERT Backbone v2.1<br/>
              Fine-tuned: PHP Webshells<br/>
              Calibration: Calibrated
            </p>
          </div>
        </aside>

        {/* Workspace */}
        <main className="flex-1 min-w-0">
          {activeTab === "analysis" ? (
            <div className="grid grid-cols-12 gap-6 h-full" id="report-area">
              <div className="col-span-12 xl:col-span-8 bg-[#1e293b] rounded-[2rem] border border-slate-800 overflow-hidden flex flex-col shadow-2xl">
                <div className="px-6 py-4 border-b border-slate-800 flex justify-between items-center bg-slate-900/40">
                  <div className="flex items-center gap-4">
                    <div className="flex gap-1.5">
                      <div className="w-3 h-3 rounded-full bg-red-500/20 border border-red-500/40"></div>
                      <div className="w-3 h-3 rounded-full bg-yellow-500/20 border border-yellow-500/40"></div>
                      <div className="w-3 h-3 rounded-full bg-green-500/20 border border-green-500/40"></div>
                    </div>
                    <div className="flex items-center gap-2 border-l border-slate-700 pl-4">
                      <FileCode size={16} className="text-slate-500" />
                      <span className="text-[11px] font-mono text-slate-400 uppercase tracking-widest font-bold">
                        {viewMode === 'original' ? 'raw_source.php' : 'normalized_output.php'}
                      </span>
                    </div>
                  </div>
                  <div className="flex bg-slate-950/80 rounded-xl p-1 border border-slate-800">
                    <button onClick={() => setViewMode("original")} className={`px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${viewMode === 'original' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}>RAW</button>
                    <button onClick={() => setViewMode("normalized")} className={`px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${viewMode === 'normalized' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}>DEOBFUSCATED</button>
                  </div>
                </div>
                <div className="flex-1">
                  <Editor
                    height="100%"
                    theme="vs-dark"
                    defaultLanguage="php"
                    value={results ? (viewMode === "original" ? results.original_code : results.normalized_code) : code}
                    onMount={(editor) => setEditorRef(editor)}
                    options={{ 
                      minimap: { enabled: false }, 
                      fontSize: 14, 
                      fontFamily: "'Fira Code', monospace",
                      padding: { top: 24 },
                      glyphMargin: true,
                      readOnly: true,
                      renderLineHighlight: 'all'
                    }}
                  />
                </div>
              </div>
              
              <div className="col-span-12 xl:col-span-4 flex flex-col gap-6">
                {results ? (
                  <div className="animate-in fade-in slide-in-from-right duration-500">
                    <RiskProfile data={results} />
                  </div>
                ) : (
                  <div className="h-full border-2 border-dashed border-slate-800 rounded-[2rem] flex flex-col items-center justify-center p-12 text-center opacity-50 hover:opacity-100 transition-opacity">
                    <div className="w-20 h-20 bg-slate-800 rounded-full flex items-center justify-center mb-6 shadow-inner">
                      <ShieldCheck size={40} className="text-slate-700" />
                    </div>
                    <h3 className="text-lg font-bold text-slate-300">Awaiting Payload</h3>
                    <p className="text-xs text-slate-500 mt-2 max-w-[200px] leading-relaxed">
                      Upload a PHP script to extract semantic intent and calibrate threat probability.
                    </p>
                  </div>
                )}
              </div>
            </div>
          ) : (
            <StatisticsTab />
          )}
        </main>
      </div>
    </div>
  );
}

export default App;
